head.script:
scwin.memJson;
scwin.sysAdminYn;
scwin.empNo;
scwin.vCurDate;
scwin.vFirDate;
scwin.isRetrieve;
scwin.vAcctDeptCd;
scwin.CoCd;
scwin.CoClsCd;

scwin.interval01;
scwin.comboRtnFlag01;
scwin.comboRtnFlag02;
scwin.udc_objNm;
scwin.ibx_supplyDt_oldVal;
scwin.ibx_supplyDt_orgFlag = false;

scwin.onpageload = function() {
    //전역변수값 셋팅함수.
	scwin.initSetVal();

    ibx_ed_slipNo.hide();

    const codeOptions1 = [
        { grpCd: "FI066", compID: "lc_pchsSellCls" },  //신고옵션 콤보 
        { grpCd: "FI067", compID: "lc_modRsnCd" },  //수정사유 콤보
    ];
    $c.data.setCommonCode(codeOptions1, scwin.commonCodeCallBack01);

    scwin.interval01 = setInterval(async function() {
        if(scwin.comboRtnFlag01 == true && scwin.comboRtnFlag02 == true) {
            clearInterval(scwin.interval01);
            //초기화
  	        await scwin.initOnload();
        }
    }, 300);
};

scwin.onUdcCompleted = function() {
    btn_co.hide();

    ed_crn.setAllowChar("0-9");
    ed_drawEmpNo.setAllowChar("0-9");
    ed_coCd.setAllowChar("0-9");

    scwin.comboRtnFlag02 = true;
};



scwin.initSetVal = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.sysAdminYn = scwin.memJson.sysAdminYn;
    scwin.empNo = scwin.memJson.empNo;

    /*
    String vCurDate = sDate.getDate("");  // 서버를 기준으로 현재 날짜 반환
	String vFirDate = sDate.getPrevDate(vCurDate,5);
    */
    debugger;
    scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.vFirDate = $c.date.addDate(scwin.vCurDate, -5);

    if(scwin.vFirDate.substring(0,6) != scwin.vCurDate.substring(0,6)){
        scwin.vFirDate = scwin.vCurDate.substring(0,6) + "01";
    }

    scwin.isRetrieve = false;
    scwin.vAcctDeptCd = scwin.memJson.acctDeptCd;
    scwin.CoCd = scwin.memJson.coCd;
    scwin.CoClsCd = scwin.memJson.coClsCd;
};

scwin.commonCodeCallBack01 = function() {
    scwin.comboRtnFlag01 = true;
};

scwin.initOnload = async function() {
    ed_coCd.setValue(scwin.CoCd);
    ibx_hid_coClsCd.setValue(scwin.CoClsCd);
    await scwin.f_PopUpCompanyInfo('T');
    debugger;
    ed_spplyDtSt.setValue(scwin.vFirDate);
    ed_spplyDtEnd.setValue(scwin.vCurDate);

    lc_qryConKnd.setValue("공급일자");
    lc_selpchClsCd.setValue("C");

    ed_spplyDtSt.focus();

    ibx_email.setReadOnly(true);

    if(ACConstants.CO_CD_DONGBU != scwin.CoCd && scwin.sysAdminYn != 1) {
        $c.gus.cfDisableObjects([ed_coCd, ed_coNm]);
    } else {
        ed_coCd.setValue(ACConstants.CO_CD_DONGBU);
    }

    //작성자 사번을 사용자 세션정보의 사번으로 자동 세팅(화면공학, 김미혜)
    ed_drawEmpNo.setValue(scwin.empNo);


    $c.gus.cfDisableObjects([lc_pchsSellCls
                    , ibx_selpchClsNm
                    , ibx_clntNm
                    , ibx_slipAcctDeptNm
                    , ibx_empNm
                    , ibx_supplierCrn
                    , ibx_spplyAmt
                    , ibx_vat
                    , lc_modRsnCd
                    , ibx_slipNo
                    , ibx_documentidentifier]
                    );
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    if(lc_qryConKnd.getValue() == "전표번호") {
        let ret = await $c.gus.cfValidate([ibx_ed_slipNo]);
        if(!ret){
            return;
        }       
    } else if(lc_qryConKnd.getValue() == "공급일자") {
        if($c.gus.cfIsNull(ed_spplyDtSt.getValue())){
           await $c.win.alert("공급일자는 필수 입니다.");
           ed_spplyDtSt.focus();
           return;
        }
        if($c.gus.cfIsNull(ed_spplyDtEnd.getValue())){
           await $c.win.alert("공급일자는 필수 입니다.");
           ed_spplyDtEnd.focus();
           return;
        }
        /*
        let ret = $c.gus.cfValidateValue(ed_spplyDtSt.getValue().trim().replace(" ",""), "date=YYYYMMDD");
        if(!ret){
           await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
           ed_spplyDtSt.focus();
           return;
        }
        */

        var fromDt = ed_spplyDtSt.getValue();
        if (!$c.date.isDate(fromDt) ){
            await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
            ed_spplyDtSt.focus();
            return;
        }

        /*
        ret = $c.gus.cfValidateValue(ed_spplyDtEnd.getValue().trim().replace(" ",""), "date=YYYYMMDD");

        if(!ret){
           await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
           ed_spplyDtEnd.focus();
           return;
        }
        */

        var endDt  = ed_spplyDtEnd.getValue();
        if (!$c.date.isDate(endDt) ){
            await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
            ed_spplyDtEnd.focus();
            return;
        }

        //조회시작일자가 더 클경우 체크
	    if (!$c.gus.cfIsAfterDate(ed_spplyDtSt.getValue(), ed_spplyDtEnd.getValue())) {
	        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
	        return;
	    }
    }


    ds_accountDetail.removeAll();
    dma_accountDetail.set("documentidentifier", "");
    dma_accountDetail.set("slipNo", "");
    dma_accountDetail.set("documentfunccode", "");
    dma_accountDetail.set("demandercontact", "");
    dma_accountDetail.set("sellPshcCd", "");
    dma_accountDetail.set("acctDeptNm", "");
    dma_accountDetail.set("drawEmpNo", "");
    dma_accountDetail.set("drawEmpNm", "");
    dma_accountDetail.set("demanderidentifier", "");
    dma_accountDetail.set("supplyamount", "");
    dma_accountDetail.set("taxamount", "");
    dma_accountDetail.set("spplyDt", "");
    dma_accountDetail.set("modRsnCd", "");
    dma_accountDetail.set("clntNo", "");
    dma_accountDetail.set("clntNm", "");
    dma_accountDetail.set("orgVatNo", "");
    dma_accountDetail.set("amendmentstatuscode", "");
    dma_accountDetail.set("demanderperson", "");
    dma_accountDetail.set("demanderdepartment", "");
    dma_accountDetail.set("remark", "");
    dma_accountDetail.set("demandercorpregnum", "");
    dma_accountDetail.set("coCdTemp", "");

    dma_search.set("slipNo", ibx_ed_slipNo.getValue());


    scwin.isRetrieve = true;
	//submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_search);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_search_submitdone();
    }
};

scwin.sbm_search_submitdone = async function (e) {
    tbx_totalRows.setValue(ds_account.getRowCount());

    if(ds_account.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);

        ds_accountDetail.removeAll();
        dma_accountDetail.set("documentidentifier", "");
        dma_accountDetail.set("slipNo", "");
        dma_accountDetail.set("documentfunccode", "");
        dma_accountDetail.set("demandercontact", "");
        dma_accountDetail.set("sellPshcCd", "");
        dma_accountDetail.set("acctDeptNm", "");
        dma_accountDetail.set("drawEmpNo", "");
        dma_accountDetail.set("drawEmpNm", "");
        dma_accountDetail.set("demanderidentifier", "");
        dma_accountDetail.set("supplyamount", "");
        dma_accountDetail.set("taxamount", "");
        dma_accountDetail.set("spplyDt", "");
        dma_accountDetail.set("modRsnCd", "");
        dma_accountDetail.set("clntNo", "");
        dma_accountDetail.set("clntNm", "");
        dma_accountDetail.set("orgVatNo", "");
        dma_accountDetail.set("amendmentstatuscode", "");
        dma_accountDetail.set("demanderperson", "");
        dma_accountDetail.set("demanderdepartment", "");
        dma_accountDetail.set("remark", "");
        dma_accountDetail.set("demandercorpregnum", "");
        dma_accountDetail.set("coCdTemp", "");

        $c.gus.cfDisableObjects([ibx_supplyDt]);
    } else {
        gr_taxInvoc.setFocusedCell(0, 0);
        //하기로직 불필요 dataList row 변경되면 상세 조회처리 하는 로직존재.
        /*
        if (ds_account.getRowCount() > 0 && ds_account.getCellData(0, "documentidentifier") != "") {

            dma_search2.set("documentidentifier", ds_account.getCellData(0, "documentidentifier"));
            dma_search2.set("slipNo", ds_account.getCellData(0, "slipNo"));
            dma_search2.set("mainkey", ds_account.getCellData(0, "mainkey"));

            await scwin.f_retrieveDetail();
            $c.gus.cfEnableObjects([ibx_supplyDt]);
        }
        */
    }

    scwin.isRetrieve = false;
};


//-------------------------------------------------------------------------
// 조회상세
//-------------------------------------------------------------------------
scwin.f_retrieveDetail = async function (e) {
    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_searchDetail);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_searchDetail_submitdone();
    }
};

scwin.sbm_searchDetail_submitdone = async function (e) {
    if( ds_accountDetail.getRowCount() == 0 ){
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);	
	} else {
        dma_accountDetail.set("documentidentifier", ds_accountDetail.getCellData(0, "documentidentifier"));
        dma_accountDetail.set("slipNo", ds_accountDetail.getCellData(0, "slipNo"));
        dma_accountDetail.set("documentfunccode", ds_accountDetail.getCellData(0, "documentfunccode"));
        dma_accountDetail.set("demandercontact", ds_accountDetail.getCellData(0, "demandercontact"));
        dma_accountDetail.set("sellPshcCd", ds_accountDetail.getCellData(0, "sellPshcCd"));
        dma_accountDetail.set("acctDeptNm", ds_accountDetail.getCellData(0, "acctDeptNm"));
        dma_accountDetail.set("drawEmpNo", ds_accountDetail.getCellData(0, "drawEmpNo"));
        dma_accountDetail.set("drawEmpNm", ds_accountDetail.getCellData(0, "drawEmpNm"));
        dma_accountDetail.set("demanderidentifier", ds_accountDetail.getCellData(0, "demanderidentifier"));
        dma_accountDetail.set("supplyamount", ds_accountDetail.getCellData(0, "supplyamount"));
        dma_accountDetail.set("taxamount", ds_accountDetail.getCellData(0, "taxamount"));
        dma_accountDetail.set("spplyDt", ds_accountDetail.getCellData(0, "spplyDt"));
        dma_accountDetail.set("modRsnCd", ds_accountDetail.getCellData(0, "modRsnCd"));
        dma_accountDetail.set("clntNo", ds_accountDetail.getCellData(0, "clntNo"));
        dma_accountDetail.set("clntNm", ds_accountDetail.getCellData(0, "clntNm"));
        dma_accountDetail.set("orgVatNo", ds_accountDetail.getCellData(0, "orgVatNo"));
        dma_accountDetail.set("amendmentstatuscode", ds_accountDetail.getCellData(0, "amendmentstatuscode"));
        dma_accountDetail.set("demanderperson", ds_accountDetail.getCellData(0, "demanderperson"));
        dma_accountDetail.set("demanderdepartment", ds_accountDetail.getCellData(0, "demanderdepartment"));
        dma_accountDetail.set("remark", ds_accountDetail.getCellData(0, "remark"));
        dma_accountDetail.set("demandercorpregnum", ds_accountDetail.getCellData(0, "demandercorpregnum"));
        dma_accountDetail.set("coCdTemp", ds_accountDetail.getCellData(0, "coCdTemp"));

        scwin.ibx_supplyDt_oldVal = dma_accountDetail.get("spplyDt");

		//이메일오류일경우 이메일 수정가능하도록
		scwin.f_setObjecInit();
	}
};


//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_srchCond,[ed_coCd,ed_coNm,ibx_hid_coClsCd]);

	ed_spplyDtSt.setValue(scwin.vFirDate);
	ed_spplyDtEnd.setValue(scwin.vCurDate);
	ed_spplyDtSt.focus();
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if(ds_accountDetail.getRowCount()==0) {
        await $c.win.alert("조회된 내역이 없습니다.");
        return;
    }

    if($c.gus.cfIsNull(dma_accountDetail.get("spplyDt"))){
       await $c.win.alert("공급일자는 필수 입니다.");
       ibx_supplyDt.focus();
       return;
    }

    var spplyDt  = dma_accountDetail.get("spplyDt").trim().replace(" ","");
    if((!$c.date.isDate(spplyDt)) || spplyDt.length != 8){
       await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
       ibx_supplyDt.focus();
       return;
    }

    /*
    var orgSpplyDtMonth = scwin.ibx_supplyDt_oldVal.substring(4,6);
    var spplyDtMonth = dma_accountDetail.get("spplyDt").substring(4,6);

    if(orgSpplyDtMonth != spplyDtMonth){
        await $c.win.alert("공급일자는 같은 월만 변경 가능 합니다.\n\n다른 월로 변경할 시에는 재경에 문의 하시기 바랍니다.");
        return;
    }
    */



    // 공급하는자종사업장번호 체크
    var demandercorpregnum_NumChk=/^[0-9]{0,4}$/;  // 종사업장번호 패턴
	var demandercorpregnum_Check = ibx_demandercorpregnum.getValue();
	if(	!demandercorpregnum_NumChk.test(demandercorpregnum_Check)){
			await $c.win.alert("종사업장번호는 4자리 숫자로 입력해주십시오.");
			return;
	}

	dma_accountDetail.set("coCdTemp", ed_coCd.getValue());

    let rtn = await $c.win.confirm("거래처 재발급을 하시겠습니까?");
    if(!rtn){
        return;
    }

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_saveAccount);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_saveAccount_submitdone();
    }
};

scwin.sbm_saveAccount_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_openPopUp  = async function (callObj, flag, check) {
    switch (flag) {
		// 거래처사업자번호 팝업
  		case "1" :
            var param ="";
            callObj.setSelectId("retrieveCrnInfo");
            scwin.udc_objNm = "udc_crn";
			await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
                                    ed_crn.getValue().trim(),ed_crnNm.getValue(),check,null,null,null,null,param,null,null,null,null
  			);

            break;

        // 작성자 팝업
  		case "2" :
            callObj.setSelectId("retrieveAcEmpInfo");
            scwin.udc_objNm = "udc_drawEmp";
			await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
                                    ed_drawEmpNo.getValue().trim(),ed_drawEmpNm.getValue(),check,null,null,null,null,param,null,null,null,null
  			);

            break;

        // E-mail 팝업
  		case "3" :
            if(ds_accountDetail.getRowCount() == 0){
               return;
            }
            // 거래처 email 조회
            var where = "";
            var code = ds_accountDetail.getCellData(0,"clntNo");
            var name = ds_accountDetail.getCellData(0,"clntNm");

            callObj.setSelectId("retrieveClntEmail");
            scwin.udc_objNm = "udc_email";
			await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
                                    code,"","F",null,null,null,null,null,null,null,null,null
  			);

            break;
	}
};

scwin.udc_AllInOne_callBackFunc = function (rtnList) {
    let codeObj;
    let nameObj;

    if(scwin.udc_objNm == "udc_crn") {
        codeObj = ed_crn;
        nameObj = ed_crnNm;

        scwin.f_resultPopEd(codeObj, nameObj, ed_crn_H, rtnList);
    } else if(scwin.udc_objNm == "udc_drawEmp") {
        codeObj = ed_drawEmpNo;
        nameObj = ed_drawEmpNm;

        scwin.f_resultPopEd(codeObj, nameObj, ed_drawEmpNo_H, rtnList);
    } else if(scwin.udc_objNm == "udc_email") {
        if(typeof(rtnList) != "undefined"){
            if ( rtnList != null) {
                if (rtnList[0] == "N/A") {
                    return;
                }

                ibx_email.setValue(rtnList[0]);
                ibx_hid_demanderperson.setValue(rtnList[3]);
                ibx_hid_demanderdepartment.setValue(rtnList[4]);
            }else{

            }
        }
    }
};

//-------------------------------------------------------------------------
// 팝업체크
//-------------------------------------------------------------------------
scwin.f_checkPopEd = async function (callObj, strCd, strNm, hiddenCd, flag) {
    if (strCd.getValue().trim() == hiddenCd.getValue()) {
        return;
    }

	strNm.setValue("");
	hiddenCd.setValue("");

	if (strCd.getValue().trim() != "") {
		await scwin.f_openPopUp(callObj, flag, 'T');
	}
};


//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd,strNm,hiddenCd,rtnList) {
    if (rtnList != null ) {
	   	if (rtnList[0] == "N/A") {
			return;
		}
		strCd.setValue(rtnList[0]);	// 코드
		strNm.setValue(rtnList[1]);	// 명
		hiddenCd.setValue(rtnList[0]);  // 히든값
    } else {
    	strCd.setValue("");
		strNm.setValue("");
		hiddenCd.setValue("");
	}
};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {
    var sheetTitle  = "전자세금계산서신고내역";
    var totCnt = ds_account.getRowCount();

    const options = {
        fileName: sheetTitle,
        sheetName : sheetTitle
    };

    if( totCnt != 0){
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if(cfrm){
            $c.data.downloadGridViewExcel(gr_taxInvoc, options);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);    
    }


};

//-------------------------------------------------------------------------
// Dataset DEBUG
//-------------------------------------------------------------------------
scwin.f_setObjecInit = function () {
    if ( scwin.vAcctDeptCd =="00009"){
 		$c.gus.cfEnableObj(lc_pchsSellCls, true);
 	}
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    udc_co.setSelectId("retrieveDongbuGroupCompanyInfo");
    await udc_co.cfCommonPopUp(scwin.udc_co_callBackFunc,
        ed_coCd.getValue(), ed_coNm.getValue(),
        pWinCloseTF, null, null, null, null, 
        null, null, null, null, null);
};

scwin.udc_co_callBackFunc = function (rtnList) {
    // SET
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }

        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명
        //ed_coCd.hidVal = rtnList[0];  // 히든값
    } else {
        ed_coCd.setValue("");   // 코드
        ed_coNm.setValue("");   // 회사명
        //ed_coCd.hidVal = ""; 
    }
}; 











scwin.lc_qryConKnd_onchange = function (info) {
    if(lc_qryConKnd.getValue() == "전표번호"){
        //div_qryConKnd1.style.display = 'none';
        //div_qryConKnd2.style.display = 'block';
        udc_fromTo.hide();
        ibx_ed_slipNo.show("");
    } else {
        //div_qryConKnd1.style.display = 'block';
        //div_qryConKnd2.style.display = 'none';
        udc_fromTo.show("");
        ibx_ed_slipNo.hide();
    }
};

//거래처사업자번호 코드 focus out 시
scwin.udc_crn_onblurCodeEvent = async function (e) {
    await scwin.f_checkPopEd(udc_crn, ed_crn, ed_crnNm, ed_crn_H, '1');
};
//거래처사업자번호 명 변경시
scwin.udc_crn_onviewchangeNameEvent = async function (info) {
    await scwin.f_openPopUp(udc_crn,'1','F');
};
//거래처사업자번호 돋보기 버튼 클릭시
scwin.udc_crn_onclickEvent = async function (e) {
    await scwin.f_openPopUp(udc_crn,'1','F')
};

//작성자 코드 focus out 시
scwin.udc_drawEmp_onblurCodeEvent = async function (e) {
    await scwin.f_checkPopEd(udc_drawEmp, ed_drawEmpNo, ed_drawEmpNm, ed_drawEmpNo_H, '2');
};
//작성자 명 변경시
scwin.udc_drawEmp_onviewchangeNameEvent = async function (info) {
    await scwin.f_openPopUp(udc_drawEmp, '2','T');
};
//작성자 돋보기 버튼 클릭시
scwin.udc_drawEmp_onclickEvent = async function (e) {
    await scwin.f_openPopUp(udc_drawEmp, '2','T');
