scwin.ibx_supplyDt_onchange = async function (info) {
    /*
    if(info.oldValue == undefined || info.oldValue == null || info.oldValue == "") {
        return;
    }
    */
    if(scwin.ibx_supplyDt_orgFlag) {
        scwin.ibx_supplyDt_orgFlag = false;
        return;
    }
    /*
    if($c.date.isDate(info.oldValue) && info.oldValue.length == 8) {
        scwin.ibx_supplyDt_oldVal = info.oldValue;
    }
    */

    if($c.gus.cfIsNull(info.newValue)){
        await $c.win.alert("공급일자는 필수 입니다.");
        ibx_supplyDt.focus();
        return;
    }
    debugger;
    var spplyDt  = info.newValue.trim().replace(" ","");
    if((!$c.date.isDate(spplyDt)) || spplyDt.length != 8){
        await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
        ibx_supplyDt.focus();
        return;
    }
    var orgSpplyDtMonth = info.oldValue.substring(4,6);
    var spplyDtMonth = info.newValue.substring(4,6);
    if(orgSpplyDtMonth != spplyDtMonth){
        $c.win.alert("공급일자는 같은 월만 변경 가능 합니다.\n\n다른 월로 변경할 시에는 재경에 문의 하시기 바랍니다.", scwin.alertCloseFunc());
    }
};

scwin.alertCloseFunc = function () {
    scwin.ibx_supplyDt_orgFlag = true;
    ibx_supplyDt.setValue(scwin.ibx_supplyDt_oldVal);
};

scwin.gridDate = function (val) {
    var sRtn = "";
    if(val.length == 14 || val.length == 8) {
        sRtn = val.substr(0,4) + "/" + val.substr(4,2) + "/" + val.substr(6,2);
    } else {
        sRtn = val;
    }
    return sRtn;
};

scwin.gridDateTime = function (val) {
    var sRtn = "";
    if(val.length == 14) {
        sRtn = val.substr(0,4) + "/" + val.substr(4,2) + "/" + val.substr(6,2) + " " + 
               val.substr(8,2) + ":" + val.substr(10,2) + ":" + val.substr(12,2);
    } else {
        sRtn = val;
    }
    return sRtn;
};

